// Obtener el texto del nodo anterior
const input = $json["output"];

// Buscar horarios ocupados y desocupados con regex
const ocupadosMatch = input.match(/Horarios ocupados:\s*([\s\S]*?)Horarios desocupados:/);
const libresMatch = input.match(/Horarios desocupados:\s*([\s\S]*)/);

const ocupados = ocupadosMatch ? ocupadosMatch[1].trim().replace(/\n/g, " ") : "N/A";
const libres = libresMatch ? libresMatch[1].trim().replace(/\n/g, " ") : "N/A";

// Retornar en el formato que pide n8n
return [
  {
    json: {
      resultado: `- Horarios ocupados: ${ocupados}\n- Horarios libres: ${libres}`
    }
  }
];

